def __setattr__(self, name: str, value: Any) -> None:
    if name.startswith("_"):
        object.__setattr__(self, name, value)
    else:
        self._custom_params[name] = value

def __repr__(self) -> str:
    params = [f"{k}={v!r}" for k, v in self.to_dict().items()]
    return f"TraigentConfig({', '.join(params)})"

def resolve_execution_mode(
    mode: ExecutionMode | str | None,
    *,
    default: ExecutionMode = ExecutionMode.CLOUD,
) -> ExecutionMode:
    """Normalize user-provided execution mode values into an ExecutionMode enum."""

    if mode is None:
        return default
    if isinstance(mode, ExecutionMode):
        return mode
    if isinstance(mode, str):
        normalized = mode.strip().lower()
        if not normalized:
            return default
        try:
            return ExecutionMode(normalized)
        except ValueError as exc:
            raise ValueError(
                f"execution_mode must be one of {[m.value for m in ExecutionMode]}, got '{mode}'"
            ) from exc
    raise TypeError(
        f"execution_mode must be a string or ExecutionMode, got {type(mode).__name__}"
    )

def evaluate_config(
    self, config: dict[str, Any], var_names: dict[int, str]
) -> bool:
    var_name = var_names.get(id(self.tvar))
    if var_name is None or var_name not in config:
        return True  # Missing value - constraint doesn't apply
    return self.evaluate(config[var_name])

def evaluate(self, value: Any) -> bool:
    if self.operator == "==":
        return bool(value == self.value)
    elif self.operator == "!=":
        return bool(value != self.value)
    elif self.operator == ">":
        return bool(value > self.value)
    elif self.operator == ">=":
        return bool(value >= self.value)
    elif self.operator == "<":
        return bool(value < self.value)
    elif self.operator == "<=":
        return bool(value <= self.value)
    elif self.operator == "in":
        return bool(value in self.value)
    elif self.operator == "not_in":
        return bool(value not in self.value)
    elif self.operator == "in_range":
        low, high = self.value
        return bool(low <= value <= high)
    else:
        raise ValueError(f"Unknown operator: {self.operator}")

def to_callable(
    self, var_names: dict[int, str] | None = None
) -> Callable[[dict[str, Any]], bool]:
    import warnings

    if var_names is None:
        var_names = {}
        missing_names: list[str] = []
        self._collect_tvars(var_names, missing_names)

        if missing_names:
            warnings.warn(
                f"Constraint has ParameterRange(s) without names: "
                f"{missing_names}. "
                "This may cause constraint evaluation to fail.",
                UserWarning,
                stacklevel=2,
            )

    captured_var_names = dict(var_names)

    def constraint_fn(config: dict[str, Any]) -> bool:
        return self.evaluate(config, captured_var_names)

    constraint_fn.__doc__ = self.description or "Structural constraint"
    constraint_fn.__name__ = f"constraint_{self.id or 'unnamed'}"

    return constraint_fn

def __init__(
    self,
    redis_url: str | None = None,
    session_ttl: int = 3600,
    max_sessions_per_user: int = 5,
    enable_rate_limiting: bool = True,
) -> None:
    self.session_ttl = session_ttl
    self.max_sessions_per_user = max_sessions_per_user
    self.enable_rate_limiting = enable_rate_limiting

    self.redis_client: Redis | None = None
    if redis_url and REDIS_AVAILABLE and redis:
        try:
            self.redis_client = redis.from_url(
                redis_url,
                decode_responses=True,
                socket_connect_timeout=5,
                socket_timeout=5,
            )
            self.redis_client.ping()
            self.use_redis = True
            logger.info("Session manager initialized with Redis backend")
        except Exception as e:
            logger.warning(
                f"Failed to connect to Redis: {e}. Using in-memory storage."
            )
            self.redis_client = None
            self.use_redis = False
    else:
        if redis_url and not REDIS_AVAILABLE:
            logger.warning(
                "Redis requested but not installed. Using in-memory storage."
            )
        self.redis_client = None
        self.use_redis = False

    if not self.use_redis:
        self._sessions: dict[str, dict[str, Any]] = {}
        self._user_sessions: dict[str, set[str]] = {}
        self._rate_limits: dict[str, list[float]] = {}
        logger.info("Session manager initialized with in-memory backend")

    self._token_secret = secrets.token_bytes(32)

def _require_cloud() -> None:
    """Raise FeatureNotAvailableError if cloud module is not available."""
    if not _CLOUD_AVAILABLE:
        from traigent.utils.exceptions import FeatureNotAvailableError

        raise FeatureNotAvailableError(
            "Traigent cloud integration",
            plugin_name="traigent-cloud",
            install_hint="pip install traigent[cloud]",
        )

async def optimize(
    self,
    function: Callable[..., Any],
    dataset: dict[str, Any],
    configuration_space: dict[str, Any],
    objectives: list[str],
    max_trials: int = 50,
    optimization_config: dict[str, Any | None] = None,
) -> dict[str, Any]:
    logger.info(f"Starting optimization in {self.execution_mode} mode")

    fallback_model = (
        "gpt-3.5-turbo"
        if self.execution_mode == ExecutionMode.EDGE_ANALYTICS
        else None
    )
    configuration_space, config_defaults = self._normalise_configuration_space(
        configuration_space, fallback_model=fallback_model
    )

    if not self._has_parameter_value(configuration_space.get("model")):
        raise ValueError(
            "Optimization configuration space is missing required entries: model"
        )

    if self.execution_mode == ExecutionMode.STANDARD:
        return await self._optimize_hybrid(
            function, dataset, configuration_space, objectives,
            max_trials, optimization_config or {}, config_defaults,
        )
    elif self.execution_mode == ExecutionMode.CLOUD:
        return await self._optimize_saas(
            function, dataset, configuration_space, objectives,
            max_trials, optimization_config or {}, config_defaults,
        )
    else:
        return await self._optimize_local(
            function, dataset, configuration_space, objectives,
            max_trials, optimization_config or {}, config_defaults,
        )

def _coerce_config_dict(
    config: object,
    *,
    source: str,
    current_state: str,
    expected_states: list[str],
) -> dict[str, Any]:
    """Normalize config objects to a plain dict and raise on invalid types."""
    if isinstance(config, TraigentConfig):
        return config.to_dict()
    if isinstance(config, dict):
        return dict(config)

    raise OptimizationStateError(
        f"{source} config has invalid type: {type(config).__name__}. "
        "Expected TraigentConfig or dict.",
        current_state=current_state,
        expected_states=expected_states,
    )

def get_config() -> dict[str, Any]:
    trial_ctx = get_trial_context()
    if trial_ctx is not None:
        return _coerce_config_dict(
            _get_context_config(),
            source="Trial",
            current_state="OPTIMIZING",
            expected_states=["OPTIMIZING"],
        )

    applied_config = get_applied_config()
    if applied_config is not None:
        return _coerce_config_dict(
            applied_config,
            source="Applied",
            current_state="CONFIG_APPLIED",
            expected_states=["CONFIG_APPLIED", "UNOPTIMIZED"],
        )

    context_config = cast(object, _get_context_config())
    if isinstance(context_config, dict) and context_config:
        return _coerce_config_dict(
            context_config,
            source="Context",
            current_state="CONFIG_APPLIED",
            expected_states=["CONFIG_APPLIED", "UNOPTIMIZED"],
        )
    if isinstance(context_config, TraigentConfig):
        config_dict = context_config.to_dict()
        if any(v is not None for k, v in config_dict.items() if k != "execution_mode"):
            return config_dict

    raise OptimizationStateError(
        "No config available.",
        current_state="NO_ACTIVE_CONFIG",
        expected_states=["UNOPTIMIZED", "CONFIG_APPLIED", "OPTIMIZING"],
    )

def __and__(self, other: BoolExpr) -> AndCondition:
    if not isinstance(other, BoolExpr):
        return NotImplemented
    return AndCondition((self, other))

def __or__(self, other: BoolExpr) -> OrCondition:
    if not isinstance(other, BoolExpr):
        return NotImplemented
    return OrCondition((self, other))

def __bool__(self) -> bool:
    raise TypeError(
        "BoolExpr cannot be used in boolean context. "
        "Use & | ~ operators instead of 'and', 'or', 'not'. "
    )

def normalize_constraints(
    constraints: Sequence[Constraint | BoolExpr | Callable[..., Any]] | None,
    var_names: dict[int, str] | None = None,
) -> list[Callable[[dict[str, Any]], bool]]:
    if not constraints:
        return []

    result: list[Callable[[dict[str, Any]], bool]] = []
    for i, constraint in enumerate(constraints):
        if isinstance(constraint, Constraint):
            result.append(constraint.to_callable(var_names))
        elif isinstance(constraint, BoolExpr):
            wrapped = Constraint(expr=constraint)
            result.append(wrapped.to_callable(var_names))
        elif callable(constraint):
            result.append(constraint)
        else:
            raise TypeError(
                f"constraints[{i}]: Expected Constraint, BoolExpr, or callable"
            )
    return result

def check_constraints_conflict(
    constraints: list[Constraint],
    sample_configs: list[dict[str, Any]] | None = None,
    var_names: dict[int, str] | None = None,
) -> ConstraintConflict | None:
    if not constraints or not sample_configs:
        return None

    if var_names is None:
        var_names = {}
        for c in constraints:
            c._collect_tvars(var_names, [])

    all_violations: list[tuple[dict[str, Any], list[tuple[Constraint, str]]]] = []

    for config in sample_configs:
        violations: list[tuple[Constraint, str]] = []

        for constraint in constraints:
            if not constraint.evaluate(config, var_names):
                explanation = constraint.explain(var_names)
                violations.append((constraint, explanation))

        if not violations:
            return None

        all_violations.append((config, violations))

    if all_violations and len(constraints) > 1:
        worst_config, worst_violations = max(all_violations, key=lambda x: len(x[1]))

        all_violated_constraints: dict[int, tuple[Constraint, str]] = {}
        for _config, violations in all_violations:
            for constraint, msg in violations:
                cid = id(constraint)
                if cid not in all_violated_constraints:
                    all_violated_constraints[cid] = (constraint, msg)

        return ConstraintConflict(
            constraints=[v[0] for v in all_violated_constraints.values()],
            config=worst_config,
            messages=[v[1] for v in all_violated_constraints.values()],
        )

    return None

def get_current_config() -> dict[str, Any]:
    warnings.warn(
        "get_current_config() is deprecated. Use traigent.get_config()",
        ConfigAccessWarning,
        stacklevel=2,
    )

    config = _get_context_config()

    if isinstance(config, TraigentConfig):
        return config.to_dict()
    if isinstance(config, dict):
        return dict(config)

    return {}

def override_config(
    objectives: list[str] | None = None,
    configuration_space: dict[str, Any] | None = None,
    constraints: list[Callable[..., Any]] | None = None,
    max_trials: int | None = None,
    timeout: int | None = None,
    max_total_examples: int | None = None,
    samples_include_pruned: bool | None = None,
) -> dict[str, Any]:
    override: dict[str, Any] = {}

    if objectives is not None:
        override["objectives"] = objectives

    if configuration_space is not None:
        override["configuration_space"] = configuration_space

    if constraints is not None:
        override["constraints"] = constraints

    if max_trials is not None:
        if max_trials < 1:
            raise ValueError("max_trials must be >= 1")
        override["max_trials"] = max_trials

    if timeout is not None:
        if timeout <= 0:
            raise ValueError("timeout must be > 0")
        override["timeout"] = timeout

    if max_total_examples is not None:
        if max_total_examples <= 0:
            raise ValueError("max_total_examples must be > 0")
        override["max_total_examples"] = max_total_examples

    if samples_include_pruned is not None:
        override["samples_include_pruned"] = bool(samples_include_pruned)

    return override

