def _configure_backend_url(api_url: str | None, backend_config: Any) -> None:
    if api_url:
        origin, path = backend_config.split_api_url(api_url)
        if origin:
            resolved_api_url = (
                f"{origin}{path or backend_config.get_default_api_path()}"
            )
        else:
            resolved_api_url = api_url.rstrip("/")
        _GLOBAL_CONFIG["traigent_api_url"] = resolved_api_url
        logger.info(f"Traigent backend API set to: {resolved_api_url}")
        return

    backend_api_url = backend_config.get_backend_api_url()
    _GLOBAL_CONFIG["traigent_api_url"] = backend_api_url
    logger.info(f"Traigent backend API configured: {backend_api_url}")

def _apply_config_settings(config: TraigentConfig) -> None:
    if config.execution_mode:
        _GLOBAL_CONFIG["execution_mode"] = config.execution_mode

    if config.local_storage_path:
        _GLOBAL_CONFIG["local_storage_path"] = config.local_storage_path

    if config.minimal_logging is not None:
        _GLOBAL_CONFIG["minimal_logging"] = config.minimal_logging

    if config.auto_sync is not None:
        _GLOBAL_CONFIG["auto_sync"] = config.auto_sync

    _GLOBAL_CONFIG["default_storage_backend"] = (
        "edge_analytics" if config.is_edge_analytics_mode() else "cloud"
    )

    logger.info(f"Traigent configured for {config.execution_mode} mode")

def _apply_additional_overrides(overrides: dict[str, Any]) -> None:
    for key, value in overrides.items():
        _GLOBAL_CONFIG[key] = value

def _configure_logging_settings(config: TraigentConfig | None) -> None:
    if config and config.minimal_logging:
        setup_logging(level="WARNING")
        return

    setup_logging(level=_GLOBAL_CONFIG.get("logging_level", "INFO"))

def get_global_parallel_config() -> ParallelConfig:
    raw_config = _GLOBAL_CONFIG.get("parallel_config")
    if isinstance(raw_config, ParallelConfig):
        return raw_config
    coerced = coerce_parallel_config(raw_config)
    if coerced is None:
        coerced = ParallelConfig()
    _GLOBAL_CONFIG["parallel_config"] = coerced
    return coerced

def to_dict(self) -> dict[str, Any]:
    result = {}
    for field in self.__dataclass_fields__:
        value = getattr(self, field)
        if value is not None and field != "custom_params":
            if field == "stop_sequences" and not value:
                continue
            result[field] = value
    result.update(self.custom_params)
    return result

def __post_init__(self) -> None:
    if self.temperature is not None:
        result = Validators.validate_number(
            self.temperature, "temperature", 0.0, 2.0
        )
        validate_or_raise(result)

    if self.max_tokens is not None:
        result = Validators.validate_positive_int(self.max_tokens, "max_tokens")
        validate_or_raise(result)

    if self.top_p is not None:
        result = Validators.validate_probability(self.top_p, "top_p")
        validate_or_raise(result)

    for penalty_name, penalty_value in [
        ("frequency_penalty", self.frequency_penalty),
        ("presence_penalty", self.presence_penalty),
    ]:
        if penalty_value is not None:
            result = Validators.validate_number(
                penalty_value, penalty_name, -2.0, 2.0
            )
            validate_or_raise(result)

    mode_enum = resolve_execution_mode(self.execution_mode)
    if mode_enum is ExecutionMode.PRIVACY:
        mode_enum = ExecutionMode.HYBRID
        self.privacy_enabled = True

    self.execution_mode = mode_enum.value

    if self.is_edge_analytics_mode() and self.local_storage_path:
        self.local_storage_path = str(
            Path(self.local_storage_path).expanduser().resolve()
        )

def explain(self, var_names: dict[int, str] | None = None) -> str:
    if var_names and id(self.tvar) in var_names:
        name = var_names[id(self.tvar)]
    elif self.tvar.name:
        name = self.tvar.name
    else:
        name = "parameter"

    if self.operator == "==":
        return f"{name} equals {self.value!r}"
    elif self.operator == "!=":
        return f"{name} is not {self.value!r}"
    elif self.operator == ">":
        return f"{name} is greater than {self.value}"
    elif self.operator == ">=":
        return f"{name} is at least {self.value}"
    elif self.operator == "<":
        return f"{name} is less than {self.value}"
    elif self.operator == "<=":
        return f"{name} is at most {self.value}"
    elif self.operator == "in":
        return f"{name} is one of {list(self.value)}"
    elif self.operator == "not_in":
        return f"{name} is not one of {list(self.value)}"
    elif self.operator == "in_range":
        low, high = self.value
        return f"{name} is between {low} and {high}"
    else:
        return f"{name} {self.operator} {self.value}"

def to_expression(self, var_names: dict[int, str] | str) -> str:
    if isinstance(var_names, str):
        var_name = var_names
    else:
        var_name = var_names.get(
            id(self.tvar), f"params.{self.tvar.name or 'unknown'}"
        )
    if self.operator == "in_range":
        low, high = self.value
        return f"({var_name} >= {low}) and ({var_name} <= {high})"
    elif self.operator == "in":
        return f"{var_name} in {self.value!r}"
    elif self.operator == "not_in":
        return f"{var_name} not in {self.value!r}"
    elif self.operator == "==":
        return f"{var_name} == {self.value!r}"
    elif self.operator == "!=":
        return f"{var_name} != {self.value!r}"
    else:
        return f"{var_name} {self.operator} {self.value}"

def _collect_from_expr(
    self,
    expr: BoolExpr,
    path: str,
    var_names: dict[int, str],
    missing_names: list[str],
) -> None:
    if isinstance(expr, Condition):
        if expr.tvar.name:
            var_names[id(expr.tvar)] = expr.tvar.name
        else:
            missing_names.append(path)
    elif isinstance(expr, (AndCondition, OrCondition)):
        for i, sub in enumerate(expr.conditions):
            self._collect_from_expr(sub, f"{path}[{i}]", var_names, missing_names)
    elif isinstance(expr, NotCondition):
        self._collect_from_expr(
            expr.condition, f"~{path}", var_names, missing_names
        )

def _collect_tvars(
    self,
    var_names: dict[int, str],
    missing_names: list[str],
) -> None:
    if self.expr is not None:
        self._collect_from_expr(self.expr, "expr", var_names, missing_names)
    else:
        if self.when is None or self.then is None:
            raise ValueError("Conditional constraint is missing when/then clauses")
        self._collect_from_expr(self.when, "when", var_names, missing_names)
        self._collect_from_expr(self.then, "then", var_names, missing_names)

def implies(
    when: BoolExpr,
    then: BoolExpr,
    description: str | None = None,
    id: str | None = None,
) -> Constraint:
    return Constraint(when=when, then=then, description=description, id=id)

def require(
    condition: BoolExpr,
    description: str | None = None,
    id: str | None = None,
) -> Constraint:
    return Constraint(expr=condition, description=description, id=id)

def constraints_to_callables(
    constraints: list[Constraint],
    var_names: dict[int, str] | None = None,
) -> list[Callable[[dict[str, Any]], bool]]:
    return [c.to_callable(var_names) for c in constraints]
